import math
from dataclasses import dataclass

@dataclass
class DPSGDConfig:
    """Configuration for Differentially Private SGD."""
    l2_norm_clip: float       # gradient clipping threshold (C in the paper)
    noise_multiplier: float   # noise scale = noise_multiplier * l2_norm_clip
    lot_size: int             # number of examples per lot (minibatch for DP accounting)
    epochs: int
    delta: float = 1e-5       # target delta (should be << 1/N where N = dataset size)

    @property
    def effective_noise_std(self) -> float:
        """Standard deviation of noise added per gradient (before clipping)."""
        return self.noise_multiplier * self.l2_norm_clip


def moments_accountant_epsilon(
    config: DPSGDConfig,
    n_training_examples: int,
) -> float:
    """
    Rough estimate of epsilon using the moments accountant approximation.
    Not a substitute for the full moments accountant (use tensorflow_privacy
    or autodp in production). For illustrative order-of-magnitude reasoning only.
    q = lot_size / N  (sampling rate)
    T = N * epochs / lot_size  (number of steps)
    epsilon ≈ q * sqrt(2 * T * ln(1/delta)) / noise_multiplier
    (valid when q << 1 and noise_multiplier > 1)
    """
    q = config.lot_size / n_training_examples
    T = n_training_examples * config.epochs / config.lot_size
    return q * math.sqrt(2 * T * math.log(1 / config.delta)) / config.noise_multiplier


# Practical trade-offs:
# noise_multiplier=1.1, l2_norm_clip=1.0, delta=1e-5, N=1M, epochs=3
# → epsilon ≈ 8 (reasonable; model quality similar to non-DP at this scale)

# noise_multiplier=0.5 → epsilon grows fast; memorization risk increases
# noise_multiplier=2.0 → very low epsilon; model quality often degrades significantly

def dp_training_recommendation(
    dataset_size: int,
    sensitivity_level: str,  # "public", "sensitive", "highly_sensitive"
) -> dict:
    """
    Return a recommended DP-SGD configuration based on dataset size and sensitivity.
    Highly sensitive data (medical, legal) warrants epsilon < 3.
    Sensitive data warrants epsilon < 8.
    Public domain data: DP may be optional.
    """
    if sensitivity_level == "highly_sensitive":
        return {"noise_multiplier": 1.5, "l2_norm_clip": 1.0, "target_epsilon": 3.0,
                "note": "Expect 5-15% accuracy degradation; necessary for PII-heavy data"}
    elif sensitivity_level == "sensitive":
        return {"noise_multiplier": 1.1, "l2_norm_clip": 1.0, "target_epsilon": 8.0,
                "note": "Reasonable quality-privacy balance for most use cases"}
    else:
        return {"noise_multiplier": None, "note": "DP optional; focus on deduplication and filtering"}

import hashlib
from dataclasses import dataclass, field

@dataclass
class DeduplicationStats:
    total_docs: int
    exact_duplicates_removed: int
    near_duplicates_removed: int
    retained: int

    @property
    def dedup_rate(self) -> float:
        return 1.0 - self.retained / max(self.total_docs, 1)


def exact_dedup(documents: list[str]) -> tuple[list[str], int]:
    """Remove exact duplicate documents using SHA-256 hashes."""
    seen: set[str] = set()
    unique: list[str] = []
    for doc in documents:
        h = hashlib.sha256(doc.encode()).hexdigest()
        if h not in seen:
            seen.add(h)
            unique.append(doc)
    return unique, len(documents) - len(unique)


def minhash_signature(text: str, n_hashes: int = 128, shingle_size: int = 5) -> list[int]:
    """
    Compute a MinHash signature for Jaccard similarity estimation.
    Each hash value is the minimum hash of all shingles under a hash function
    parameterised by a large prime (simplified implementation).
    """
    words = text.lower().split()
    shingles = set(
        " ".join(words[i:i+shingle_size])
        for i in range(max(1, len(words) - shingle_size + 1))
    )
    sig = []
    for seed in range(n_hashes):
        min_h = min(
            int(hashlib.md5((str(seed) + s).encode()).hexdigest(), 16)
            for s in shingles
        ) if shingles else 0
        sig.append(min_h)
    return sig


def jaccard_from_minhash(sig_a: list[int], sig_b: list[int]) -> float:
    """Estimate Jaccard similarity from two MinHash signatures."""
    if len(sig_a) != len(sig_b):
        raise ValueError("Signatures must have the same length")
    matches = sum(a == b for a, b in zip(sig_a, sig_b))
    return matches / len(sig_a)


# Near-dedup at Jaccard >= 0.8 removes paraphrase mirrors.
# Threshold choice: 0.8 is standard for web data (Lee et al. 2022 / C4 / RefinedWeb).
